import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";

function Cart()
{
    const navigate = useNavigate();
    const { category, slug } = useParams();
    const [cart, setCart] = useState([]);
    const [loading, setLoading] = useState(true);


    useEffect(() =>
    {
        let isMounted = true;

        axios.get(`/api/cart`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setCart(res.data.cart);

                } else if (res.data.status === 401)
                {
                    navigate('/');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching product details:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category, slug, navigate]);


    if (loading)
    {
        return <h4>Loading Cart...</h4>;
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Home / Cart</h6>
                </div>
            </div>

            <div className="py-4">
                <div className="container">
                    <div className="row">
                        <div className="col-md-12">

                            <div className="table-responsive">
                                <table className="table table-bordered">
                                    <thead>
                                        <tr>
                                            <th>Image</th>
                                            <th>Product</th>
                                            <th className="text-center">Price</th>
                                            <th className="text-center">Quantity</th>
                                            <th className="text-center">Total Price</th>
                                            <th>Remove</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr>
                                            <td width="10%">
                                                <img src="" alt="Prod Image" width="50px" height="50px" />
                                            </td>
                                            <td>Product Name</td>
                                            <td width="15%" className="text-center">$500</td>
                                            <td width="15%">
                                                <div className="input-group">
                                                    <button type="button" className="input-group-text">-</button>
                                                    <div className="form-control text-center">2</div>
                                                    <button type="button" className="input-group-text">+</button>
                                                </div>
                                            </td>
                                            <td width="15%" className="text-center">100</td>
                                            <td width="10%">
                                                <button type="button" className="btn btn-danger btn-sm">Remove</button>
                                            </td>
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}
export default Cart;
